import React, { useState, useEffect } from 'react';

const NowPlaying = ({ track, isPlaying, onTogglePlay, onClose }) => {
    const [currentTime, setCurrentTime] = useState('0:00');
    const [volume, setVolume] = useState(70);
    
    // Все хуки должны вызываться безусловно
    useEffect(() => {
        let interval;
        if (isPlaying) {
            interval = setInterval(() => {
                const [mins, secs] = currentTime.split(':').map(Number);
                let totalSecs = mins * 60 + secs + 1;
                const newMins = Math.floor(totalSecs / 60);
                const newSecs = totalSecs % 60;
                setCurrentTime(`${newMins}:${newSecs.toString().padStart(2, '0')}`);
            }, 1000);
        }
        return () => clearInterval(interval);
    }, [isPlaying, currentTime]);

    if (!track) return null;

    return (
        <div className="now-playing-bar">
            <div className="now-playing-left">
                <div className="now-playing-cover">🎵</div>
                <div className="now-playing-info">
                    <strong>{track.title}</strong>
                    <span>{track.artist}</span>
                </div>
            </div>

            <div className="now-playing-center">
                <div className="player-controls">
                    <button className="control-btn">⏮️</button>
                    <button className="control-btn play-pause" onClick={onTogglePlay}>
                        {isPlaying ? '⏸️' : '▶️'}
                    </button>
                    <button className="control-btn">⏭️</button>
                </div>
                <div className="progress-bar">
                    <span>{currentTime}</span>
                    <div className="progress-track">
                        <div className="progress-fill"></div>
                    </div>
                    <span>{track.duration}</span>
                </div>
            </div>

            <div className="now-playing-right">
                <div className="volume-control">
                    <span>🔊</span>
                    <div className="volume-bar">
                        <div className="volume-fill" style={{ width: `${volume}%` }}></div>
                    </div>
                </div>
                <button className="close-btn" onClick={onClose}>✖</button>
            </div>
        </div>
    );
};

export default NowPlaying;
